const table=layui.table,util=layui.util,form=layui.form;table.render({id:"tagTable",elem:"#tag",url:"/api/tag/list?user=my",page:!0,cols:[[{field:"tagId",title:"ID",width:100},{field:"content",title:"标签"},{title:"使用次数",templet:({articles:articles})=>articles.length},{title:"创建者",templet:({user:user})=>user.nickName},{title:"创建时间",templet:({createdAt:createdAt})=>util.toDateString(createdAt,"yyyy-MM-dd HH:mm")},{title:"操作",templet:()=>'<a class="layui-btn layui-btn-xs" lay-event="edit">编辑</a>\n                        <a class="layui-btn layui-btn-danger layui-btn-xs" lay-event="del">删除</a>'}]]}),table.on("tool(tag)",(function(obj){"del"===obj.event?layer.confirm("删除操作不可恢复，确定删除吗？",index=>{layer.load(2),layer.close(index),axios({method:"delete",url:"/api/tag",params:{tagId:obj.data.tagId}}).then(({data:res})=>{layer.closeAll("loading"),0===res.code?($ryTools.notify({description:res.msg}),table.reload("tagTable")):$ryTools.notify({description:res.msg,type:"error"})})}):"edit"===obj.event&&layer.confirm("还没做呢",(function(index){layer.close(index)}))})),$ry(".add-tag").click(()=>{layer.open({type:1,title:"创建标签",area:"375px",content:$ry(".addTagFrom").html(),success:(layero,index)=>{form.render(),form.on("submit(form)",(function({field:data}){layer.load(2),layer.close(index),axios({method:"post",url:"/api/tag",data:Qs.stringify(data)}).then(({data:res})=>{layer.closeAll("loading"),0===res.code?($ryTools.notify({description:res.msg}),table.reload("tagTable")):$ryTools.notify({description:res.msg,type:"error"})})}))}})});